# Definition for a binary tree node.
class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def isSameTree(self, p: TreeNode, q: TreeNode) -> bool:
        # Base case: if both trees are empty, they are the same
        if not p and not q:
            return True

        # If one tree is empty and the other is not, they are not the same
        if not p or not q:
            return False

        # If the values of the current nodes are different, the trees are not the same
        if p.val != q.val:
            return False

        # Recursively check the left and right subtrees
        return self.isSameTree(p.left, q.left) and self.isSameTree(p.right, q.right)

# Time Complexity: O(n)
# Space Complexity: O(n)
# Algorithm: Recursive depth-first search to compare the structure and values of two binary trees

class MapSum:
    def __init__(self):
        # Initialize a dictionary to store key-value pairs
        self.map = {}

    def insert(self, key: str, val: int) -> None:
        # Insert or update the key-value pair in the dictionary
        self.map[key] = val

    def sum(self, prefix: str) -> int:
        # Initialize the sum to 0
        total = 0
        # Iterate over each key in the dictionary
        for key in self.map:
            # Check if the key starts with the given prefix
            if key.startswith(prefix):
                # If it does, add the value to the total sum
                total += self.map[key]
        # Return the total sum
        return total

class Solution:
    def solve(self, operations):
        map_sum = MapSum()
        result = []
        for op in operations:
            if op[0] == "MapSum":
                result.append(None)
            elif op[0] == "insert":
                map_sum.insert(op[1], op[2])
                result.append(None)
            elif op[0] == "sum":
                result.append(map_sum.sum(op[1]))
        return result

# Time Complexity: O(n*m) where n is the number of operations and m is the maximum length of a key
# Space Complexity: O(n) where n is the number of key-value pairs
# Algorithm: Using a dictionary to store key-value pairs and iterating over the keys to calculate the sum for a given prefix

# Definition for singly-linked list.
class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def detectCycle(self, head: ListNode) -> ListNode:
        # Phase 1: Detecting the cycle using Floyd's Tortoise and Hare algorithm
        tortoise = head
        hare = head
        while hare is not None and hare.next is not None:
            tortoise = tortoise.next
            hare = hare.next.next
            if tortoise == hare:
                break

        # If there is no cycle, return None
        if hare is None or hare.next is None:
            return None

        # Phase 2: Finding the start of the cycle
        tortoise = head
        while tortoise != hare:
            tortoise = tortoise.next
            hare = hare.next

        return tortoise

class Solution:
    def maxProfit(self, prices: list[int]) -> int:
        buy1, sell1, buy2, sell2 = float('-inf'), 0, float('-inf'), 0
        for price in prices:
            buy1 = max(buy1, -price)
            sell1 = max(sell1, buy1 + price)
            buy2 = max(buy2, sell1 - price)
            sell2 = max(sell2, buy2 + price)
        return sell2
